#include <stdio.h>
int min(int a, int b) { return a < b ? a : b; }
int main() {
    int n;
    scanf("%d", &n);
    int durations[n];
    int total = 0;
    for (int i = 0; i < n; i++) {
        scanf("%d", &durations[i]);
        total += durations[i];
    }
    int dp[n + 1][total + 1];
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= total; j++) {
            dp[i][j] = 0;
        }
    }
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= total; j++) {
            if (durations[i - 1] > j) {
                dp[i][j] = dp[i - 1][j];
            } else {
                dp[i][j] = min(dp[i - 1][j], dp[i - 1][j - durations[i - 1]] + durations[i - 1]);
            }
        }
    }
    printf("%d\n", min(dp[n][total / 2], dp[n][total / 2 + 1]));
    return 0;
}

