def min_diff(n, durations):
    total = sum(durations)
    dp = [[0] * (total + 1) for _ in range(n + 1)]
    for i in range(1, n + 1):
        for j in range(1, total + 1):
            if durations[i - 1] > j:
                dp[i][j] = dp[i - 1][j]
            else:
                dp[i][j] = min(dp[i - 1][j], dp[i - 1][j - durations[i - 1]] + durations[i - 1])
    return min(dp[n][total // 2], dp[n][total // 2 + 1])

n = int(input())
durations = list(map(int, input().split()))
print(min_diff(n, durations))

